def gen(rng, size):
    n = rng.randint(2, max(2, min(size, 30)))
    s = ''.join(rng.choice('ab') for _ in range(n))
    if rng.random() < 0.5:
        r = rng.randint(0, n - 1)
        t = s[n - r:] + s[:n - r]
    else:
        t = ''.join(rng.choice('ab') for _ in range(n))
    k = rng.randint(1, 150)
    return [s, t, k]

