class Solution:
    def numberOfWays(self, s: str, t: str, k: int) -> int:
        MOD = 10 ** 9 + 7
        n = len(s)

        def rotate(r):
            return s[n - r:] + s[:n - r]

        targets = [r for r in range(n) if rotate(r) == t]

        dp = [0] * n
        dp[0] = 1
        for _ in range(k):
            total = sum(dp) % MOD
            dp = [(total - dp[x]) % MOD for x in range(n)]

        return sum(dp[r] for r in targets) % MOD

