class Solution:
    def numberOfWays(self, s: str, t: str, k: int) -> int:
        MOD = 10 ** 9 + 7
        n = len(s)

        def kmp_positions(text, pattern):
            m = len(pattern)
            if m == 0:
                return []
            lps = [0] * m
            length = 0
            i = 1
            while i < m:
                if pattern[i] == pattern[length]:
                    length += 1
                    lps[i] = length
                    i += 1
                elif length != 0:
                    length = lps[length - 1]
                else:
                    lps[i] = 0
                    i += 1
            positions = []
            i = j = 0
            while i < len(text):
                if text[i] == pattern[j]:
                    i += 1
                    j += 1
                    if j == m:
                        positions.append(i - j)
                        j = lps[j - 1]
                elif j != 0:
                    j = lps[j - 1]
                else:
                    i += 1
            return positions

        matches = kmp_positions(s + s, t)
        cnt = sum(1 for pos in matches if pos < n)

        def mat_mult(a, b):
            return [
                [(a[0][0] * b[0][0] + a[0][1] * b[1][0]) % MOD, (a[0][0] * b[0][1] + a[0][1] * b[1][1]) % MOD],
                [(a[1][0] * b[0][0] + a[1][1] * b[1][0]) % MOD, (a[1][0] * b[0][1] + a[1][1] * b[1][1]) % MOD],
            ]

        def mat_pow(m, p):
            result = [[1, 0], [0, 1]]
            base = m
            while p > 0:
                if p & 1:
                    result = mat_mult(result, base)
                base = mat_mult(base, base)
                p >>= 1
            return result

        M = [[0, (n - 1) % MOD], [1, (n - 2) % MOD]]
        Mk = mat_pow(M, k)
        a_k = Mk[0][0]
        b_k = Mk[1][0]

        if s == t:
            ans = (a_k + (cnt - 1) * b_k) % MOD
        else:
            ans = (cnt * b_k) % MOD
        return ans % MOD

