var numberOfWays = function(s, t, k) {
    const MOD = 1000000007n;
    const n = s.length;

    function kmpPositions(text, pattern) {
        const m = pattern.length;
        if (m === 0) return [];
        const lps = new Array(m).fill(0);
        let length = 0, i = 1;
        while (i < m) {
            if (pattern[i] === pattern[length]) {
                length++;
                lps[i] = length;
                i++;
            } else if (length !== 0) {
                length = lps[length - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
        const positions = [];
        let ti = 0, pj = 0;
        while (ti < text.length) {
            if (text[ti] === pattern[pj]) {
                ti++; pj++;
                if (pj === m) {
                    positions.push(ti - pj);
                    pj = lps[pj - 1];
                }
            } else if (pj !== 0) {
                pj = lps[pj - 1];
            } else {
                ti++;
            }
        }
        return positions;
    }

    const matches = kmpPositions(s + s, t);
    let cnt = 0;
    for (const pos of matches) if (pos < n) cnt++;

    function matMult(a, b) {
        return [
            [(a[0][0] * b[0][0] + a[0][1] * b[1][0]) % MOD, (a[0][0] * b[0][1] + a[0][1] * b[1][1]) % MOD],
            [(a[1][0] * b[0][0] + a[1][1] * b[1][0]) % MOD, (a[1][0] * b[0][1] + a[1][1] * b[1][1]) % MOD],
        ];
    }

    function matPow(m, p) {
        let result = [[1n, 0n], [0n, 1n]];
        let base = m;
        while (p > 0n) {
            if (p & 1n) result = matMult(result, base);
            base = matMult(base, base);
            p >>= 1n;
        }
        return result;
    }

    const nBig = BigInt(n);
    const M = [[0n, (nBig - 1n) % MOD], [1n, (nBig - 2n + MOD) % MOD]];
    const Mk = matPow(M, BigInt(k));
    const ak = Mk[0][0];
    const bk = Mk[1][0];

    let ans;
    if (s === t) {
        ans = (ak + (((BigInt(cnt) - 1n) * bk) % MOD + MOD) % MOD) % MOD;
    } else {
        ans = (BigInt(cnt) * bk) % MOD;
    }
    return Number(((ans % MOD) + MOD) % MOD);
};
